import pytestfrom dotenv import load_dotenvfrom ragas import SingleTurnSample, MultiTurnSamplefrom ragas.messages import HumanMessage, AIMessagefrom ragas.metrics._faithfulness import Faithfulnessfrom ragas.metrics._topic_adherence import TopicAdherenceScorefrom src.llmeval.utils import get_llm_response, load_test_dataload_dotenv()filename = "src/test_data/faithfulness_parametrization_data.json"@pytest.mark.asyncio# @pytest.mark.parametrize("get_data",#                          load_test_data(filename),#                          indirect=True)async def test_topic_adherence(llm_wrapper, get_data):    topic_score = TopicAdherenceScore(llm=llm_wrapper)    score = await topic_score.multi_turn_ascore(get_data)    print("The score is", score)    assert score > 0.8@pytest.fixturedef get_data(request):    # test_data = request.param    # response_dict = get_llm_response(test_data)    conversation = [        HumanMessage(content = "How many articles are there in the Selenium Webdriver course?"),        AIMessage(content = "There are **63 articles** included in the Selenium WebDriver course."),        HumanMessage(content = "How many downloadable resources are in this course?"),        AIMessage(content = "Based on the course description, there are **three downloadable resources**"),    ]    reference =  ["""        The AI should:        1. Provide results related to the Selenium Webdriver course.        2. There are 63 articles and 3 downloadables in the course.        """]    sample = MultiTurnSample(        user_input=conversation,        reference_topics=reference    )    return sample